import cn from 'clsx'
import PropTypes from 'prop-types'
import React from 'react'
import classes from '../style/index.module.styl'

export interface BlogLayoutProps {
  /**
   * Date range of Copyright.
   */
  copyrightDate: string
  /**
   * Author's name.
   */
  authorName: string
  /**
   * Author's motto.
   */
  authorMotto: string
  /**
   * Main content.
   */
  content?: React.ReactNode
  /**
   * Footer content.
   */
  footer?: React.ReactNode
  /**
   * Display the backdrop
   */
  showBackdrop?: boolean
}

export const BlogLayoutMain: React.FC<BlogLayoutProps> = props => {
  const {
    content,
    footer,
    copyrightDate,
    authorMotto,
    authorName,
    showBackdrop = false,
  } = props

  return (
    <div className={classes.main}>
      <div className={classes.mainContent}>
        {content}
        <footer className={classes.mainFooter}>
          <span>
            © {copyrightDate} {authorName}
          </span>
          <span>{authorMotto}</span>
        </footer>
        {footer}
      </div>
      <div className={cn('backdrop', { hidden: !showBackdrop })} />
    </div>
  )
}

BlogLayoutMain.propTypes = {
  copyrightDate: PropTypes.string.isRequired,
  authorName: PropTypes.string.isRequired,
  authorMotto: PropTypes.string.isRequired,
  content: PropTypes.node,
  footer: PropTypes.node,
  showBackdrop: PropTypes.bool,
}

BlogLayoutMain.displayName = 'BlogLayoutMain'
export default BlogLayoutMain
