import screen from '@kyokuya/_shared/util/screen'
import ParticleEffectBubble from '@kyokuya/particle-bubble'
import type { ParticleEffectBubbleProps } from '@kyokuya/particle-bubble'
import { useParticleEffect2D } from '@kyokuya/particle-helper'
import ParticleEffectNest from '@kyokuya/particle-nest'
import type { ParticleEffectNestProps } from '@kyokuya/particle-nest'
import {
  PostLayoutActionsType,
  PostLayoutContext,
} from '@kyokuya/react-layout-post'
import Fab from '@material-ui/core/Fab'
import MenuOpenIcon from '@material-ui/icons/MenuOpen'
import cn from 'clsx'
import type { UIEventHandler } from 'react'
import React, { useCallback, useContext, useMemo, useRef } from 'react'
import siteMetadata from '@/config/site/metadata'
import classes from '../style/index.module.styl'
import AboutMePanel from './about-me-panel'
import Main from './main'
import NavigationPanel from './navigation-panel'
import SearchPanel from './search-panel'
import Sidebar from './sidebar'

export interface BlogLayoutProps {
  /**
   * HTML head elements.
   */
  head?: React.ReactNode
  /**
   * Main content.
   */
  content?: React.ReactNode
  /**
   * Navigation.
   */
  nav?: React.ReactNode
  /**
   * Footer content.
   */
  footer?: React.ReactNode
  /**
   * Url of pagination pages.
   */
  paginationUrl: string
  /**
   * Handle scrolling event.
   */
  onScroll?: UIEventHandler
}

const nestOptions: ParticleEffectNestProps = {
  pointColor: () => '#44c1ff',
  lineColor: () => '#fff',
  pointRadius: 1.5,
}

const bubbleOptions: ParticleEffectBubbleProps = {}

/**
 * Layout for blog layout.
 * @param props
 * @returns
 */
export function BlogLayout(props: BlogLayoutProps): React.ReactElement {
  const { author, copyright } = siteMetadata
  const magicPanelRef = useRef<HTMLDivElement>(null)
  const containerRef = useRef<HTMLDivElement>(null)

  const { magicPanelVisible, magicPanelActivated, dispatch } =
    useContext(PostLayoutContext)
  const { head, content, nav, footer, paginationUrl, onScroll } = props

  // Use particle effect when magic-panel is hidden.
  useParticleEffect2D<ParticleEffectNestProps>(
    screen.lg ? containerRef : null,
    ParticleEffectNest,
    nestOptions,
    !magicPanelVisible,
  )

  // Use particle effect when magic-panel is visible.
  useParticleEffect2D<ParticleEffectBubbleProps>(
    screen.lg ? containerRef : null,
    ParticleEffectBubble,
    bubbleOptions,
    magicPanelVisible,
  )

  // Use particle effect when magic-panel is visible.
  useParticleEffect2D<ParticleEffectBubbleProps>(
    screen.lg ? null : magicPanelRef,
    ParticleEffectBubble,
    bubbleOptions,
    magicPanelVisible,
  )

  const closeMagicPanel = useCallback<React.MouseEventHandler>(
    () =>
      dispatch({
        type: PostLayoutActionsType.TOGGLE_MAGIC_PANEL,
        payload: false,
      }),
    [dispatch],
  )

  const toggleMagicPanel = useCallback<React.MouseEventHandler>(
    e => {
      e.stopPropagation()
      dispatch({ type: PostLayoutActionsType.TOGGLE_MAGIC_PANEL })
    },
    [dispatch],
  )

  const navButtons = useMemo<
    Record<'navigation' | 'search' | 'aboutMe', React.MouseEventHandler>
  >(
    () => ({
      navigation: e => {
        e.stopPropagation()
        dispatch({
          type: PostLayoutActionsType.ACTIVE_MAGIC_PANEL,
          payload: { panel: 'navigation' },
        })
      },
      search: e => {
        e.stopPropagation()
        dispatch({
          type: PostLayoutActionsType.ACTIVE_MAGIC_PANEL,
          payload: { panel: 'search' },
        })
      },
      aboutMe: e => {
        e.stopPropagation()
        dispatch({
          type: PostLayoutActionsType.ACTIVE_MAGIC_PANEL,
          payload: { panel: 'about-me' },
        })
      },
    }),
    [dispatch],
  )

  return (
    <div
      ref={containerRef}
      className={cn(classes.container, {
        [classes.magicPanelVisible]: magicPanelVisible,
      })}
      onClick={closeMagicPanel}
    >
      {head}
      <Fab
        color="primary"
        size="small"
        className={cn(classes.pageMenuButton, {
          [classes.pageMenuButtonActivated]: magicPanelVisible,
        })}
        aria-label="toggle menu"
        onClick={toggleMagicPanel}
      >
        <MenuOpenIcon />
      </Fab>
      <div className={classes.scrollableContainer} onScroll={onScroll}>
        <div className={classes.scrollableWrapper}>
          <Sidebar
            authorName={author.name}
            authorMotto={author.motto}
            githubUrl={author.github}
            rssUrl={author.rss}
            homeUrl={author.home}
            paginationUrl={paginationUrl}
          />
          <div
            ref={magicPanelRef}
            className={cn(classes.magicPanel, classes.frostedGlassPanel)}
            onClick={e => void e.stopPropagation()}
          >
            <div className={classes.magicPanelHeader}>
              <div className={classes.magicPanelNav}>
                <span
                  key="navigation"
                  className={cn(classes.magicPanelNavItem, {
                    [classes.magicPanelNavItemActive]:
                      magicPanelActivated === 'navigation',
                  })}
                  onClick={navButtons.navigation}
                >
                  目录
                </span>
                <span
                  key="delimiter-1"
                  className={classes.magicPanelNavDelimiter}
                />
                <span
                  key="search"
                  className={cn(classes.magicPanelNavItem, {
                    [classes.magicPanelNavItemActive]:
                      magicPanelActivated === 'search',
                  })}
                  onClick={navButtons.search}
                >
                  检索
                </span>
                <span
                  key="delimiter-2"
                  className={classes.magicPanelNavDelimiter}
                />
                <span
                  key="about-me"
                  className={cn(classes.magicPanelNavItem, {
                    [classes.magicPanelNavItemActive]:
                      magicPanelActivated === 'about-me',
                  })}
                  onClick={navButtons.aboutMe}
                >
                  关于我
                </span>
              </div>
            </div>
            <div className={classes.magicPanelBody}>
              <NavigationPanel
                className={cn({
                  hidden: magicPanelActivated !== 'navigation',
                })}
              >
                {nav}
              </NavigationPanel>
              <SearchPanel
                className={cn({ hidden: magicPanelActivated !== 'search' })}
              />
              <AboutMePanel
                className={cn({
                  hidden: magicPanelActivated !== 'about-me',
                })}
              />
            </div>
          </div>
          <Main
            copyrightDate={copyright.date}
            authorName={author.name}
            authorMotto={author.motto}
            content={content}
            footer={footer}
            showBackdrop={magicPanelVisible}
          />
        </div>
      </div>
    </div>
  )
}

BlogLayout.displayName = 'BlogLayout'
export default BlogLayout
